                            const next = [...prev];

                            while (next.length <= idx) {
                              next.push(undefined!);
                            }

                            next[idx] = Number(value);

                            setValue(field, next, { shouldDirty: true, shouldValidate: true });
                          }}
                          defaultValue={Number.isInteger(score) ? String(score) : ''}
                        >
