            </div>
            {idx >= defaultSubjectLength && (
              <button
                className={cn('absolute', 'right-[-1.97rem]')}
                onClick={() => handleDeleteSubjectClick(idx)}
              >
                <XIcon className={cn('stroke-slate-300', 'w-[1rem]', 'hover:stroke-slate-500')} />
              </button>
            )}
          </div>
        );
      })}
    </div>
  );
};

