                      {
                        '!border-red-600': hasError,
                      },
                    )}
                    placeholder={idx === volunteerTimeIndex ? '시간 입력' : '입력'}
                  />
                </div>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
};

