    setValue('birth', `${year}-${month}-${day}`, { shouldValidate: true, shouldDirty: true });
  };

  const handleBirthMonthChange = (month: string) => {
    const year = birthYear || '2000';
    const day = birthDay || '01';
    setValue('birth', `${year}-${month.padStart(2, '0')}-${day}`, {
      shouldValidate: true,
      shouldDirty: true,
