              {...register('name')}
              placeholder="이름을 입력해 주세요"
              width="full"
              variant={showError && errors.name ? 'error' : null}
            />
          </CustomFormItem>
          <CustomFormItem
            text={'생년월일'}
            className={cn('gap-1')}
            required={true}
            fullWidth={true}
          >
            <div className={cn('flex', 'w-full', 'justify-between')}>
              <Select value={birthYear || ''} onValueChange={handleBirthYearChange}>
                <SelectTrigger
                  className={cn('w-[9.3785rem]', showError && errors.birth && '!border-red-600')}
                >
                  <SelectValue placeholder="연도 선택" />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    <SelectLabel>연도 선택</SelectLabel>
                    {BIRTH_YEARS.map((year) => (
                      <SelectItem key={year} value={year.toString()}>
                        {year}년
                      </SelectItem>
                    ))}
                  </SelectGroup>
                </SelectContent>
              </Select>
              <Select
                value={birthMonth ? Number(birthMonth).toString() : ''}
                onValueChange={handleBirthMonthChange}
              >
                <SelectTrigger
                  className={cn('w-[9.3785rem]', showError && errors.birth && '!border-red-600')}
                >
                  <SelectValue placeholder="월 선택" />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    <SelectLabel>월 선택</SelectLabel>
                    {BIRTH_MONTHS.map((month) => (
                      <SelectItem key={month} value={month.toString()}>
                        {month}월
                      </SelectItem>
                    ))}
                  </SelectGroup>
                </SelectContent>
              </Select>
              <Select
                value={birthDay ? Number(birthDay).toString() : ''}
                onValueChange={handleBirthDayChange}
              >
                <SelectTrigger
                  className={cn('w-[9.3785rem]', showError && errors.birth && '!border-red-600')}
                >
                  <SelectValue placeholder="일 선택" />
                </SelectTrigger>
                <SelectContent>
                  <SelectGroup>
                    <SelectLabel>일 선택</SelectLabel>
                    {BIRTH_DAYS.map((day) => (
                      <SelectItem key={day} value={day.toString()}>
                        {day}일
                      </SelectItem>
                    ))}
                  </SelectGroup>
                </SelectContent>
              </Select>
            </div>
          </CustomFormItem>
        </div>

        <div className={cn('flex', 'w-[29.75rem]', 'flex-col', 'items-start', 'gap-10')}>
          <RadioButton
            title={'성별'}
            list={sexList}
            required={true}
            selectedValue={watch('sex') || ''}
            handleOptionClick={(value) =>
              setValue('sex', value as 'MALE' | 'FEMALE', {
                shouldValidate: true,
                shouldDirty: true,
              })
            }
            error={showError && !!errors.sex}
          />

          <div className={cn('flex', 'flex-col', 'items-start', 'gap-[0.375rem]', 'w-full')}>
            <CustomFormItem
              text={'주소지'}
              className={cn('gap-1')}
              required={true}
              fullWidth={true}
            >
              <div className={cn('w-full', 'flex', 'gap-2')}>
                <Input
                  placeholder={'주소를 입력해 주세요'}
                  width="full"
                  disabled
                  {...register('address')}
                  variant={showError && errors.address ? 'error' : null}
                />

                <Button onClick={handleZipCodeButtonClick}>주소 찾기</Button>
              </div>
            </CustomFormItem>
            <Input
              placeholder="상세주소"
              width="full"
              {...register('detailAddress')}
              variant={showError && errors.detailAddress ? 'error' : null}
            />
          </div>

          <CustomFormItem
            text={'휴대폰 번호'}
            className={cn('gap-1')}
            required={true}
            fullWidth={true}
          >
            <Input placeholder={phoneNumber} disabled width="full" />
          </CustomFormItem>
        </div>
      </div>
    </div>
  );
};

export default Step1Register;

'use client';

import { useEffect } from 'react';
import {
  FormState,
  UseFormRegister,
  UseFormReset,
  UseFormSetValue,
  UseFormTrigger,
  UseFormWatch,
} from 'react-hook-form';

import { CURRENT_YEAR, NEXT_YEAR } from '@repo/constants';
import {
  DesireMajorValueEnum,
  GraduationTypeValueEnum,
  ScreeningValueEnum,
  Step2FormType,
} from '@repo/types';
import { cn } from '@repo/utils';

import { CustomFormItem, RadioButton, SearchDialog } from '../../';
import {
  Input,
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectLabel,
  SelectTrigger,
  SelectValue,
} from '../../../shadcn';

interface Step2RegisterProps {
  register: UseFormRegister<Step2FormType>;
  setValue: UseFormSetValue<Step2FormType>;
  watch: UseFormWatch<Step2FormType>;
  reset: UseFormReset<Step2FormType>;
  trigger: UseFormTrigger<Step2FormType>;
  formState: FormState<Step2FormType>;
  showError: boolean;
}

type MajorFieldType = 'firstDesiredMajor' | 'secondDesiredMajor' | 'thirdDesiredMajor';

const graduationTypeList = [
  { name: '졸업자', value: GraduationTypeValueEnum.GRADUATE },
  { name: '졸업예정', value: GraduationTypeValueEnum.CANDIDATE },
  { name: '검정고시', value: GraduationTypeValueEnum.GED },
] as const;

const majorList = [
  { name: '소프트웨어개발과', value: DesireMajorValueEnum.SW },
  { name: '스마트IoT과', value: DesireMajorValueEnum.IOT },
  { name: '인공지능(AI)과', value: DesireMajorValueEnum.AI },
] as const;

const screeningList = [
  { name: '일반전형', value: ScreeningValueEnum.GENERAL },
  { name: '사회통합전형', value: ScreeningValueEnum.SPECIAL },
  { name: '국가보훈대상자', value: ScreeningValueEnum.EXTRA_VETERANS },
  { name: '특례입학대상자', value: ScreeningValueEnum.EXTRA_ADMISSION },
] as const;

const majorIntroductions = [
  {
    name: '소프트웨어개발과',
    description: 'C, C++, JAVA, 모바일 등',
  },
  {
    name: '스마트IoT(Internet of Things)과',
    description: '리눅스, 라즈베리파이, 아두이노, 하드웨어 등',
  },
  {
    name: '인공지능(AI)과',
    description: '빅데이터, 사물인터넷, 머신러닝, 딥러닝 등',
  },
] as const;

const Step2Register = ({
  register,
  setValue,
  watch,
  reset,
  trigger,
  formState: { errors },
  showError,
}: Step2RegisterProps) => {
  const majorFieldList: MajorFieldType[] = [
    'firstDesiredMajor',
    'secondDesiredMajor',
    'thirdDesiredMajor',
  ];

  const year = watch('graduationDate').split('-')[0];
  const month = watch('graduationDate').split('-')[1];
  const classroom = watch('classroom');
  const number = watch('number');

  const isCandidate = watch('graduationType') === GraduationTypeValueEnum.CANDIDATE;
  const isGED = watch('graduationType') === GraduationTypeValueEnum.GED;

  const START_YEAR = isCandidate ? NEXT_YEAR : CURRENT_YEAR;
  const PERMIT_YEAR = isCandidate ? 1 : 5;

  const FIXED_GRADE = 3;

  useEffect(() => {
    if (!isGED && classroom && number) {
      const classroomNum = parseInt(classroom);
      const numberNum = parseInt(number);

      if (classroomNum >= 1 && classroomNum <= 12 && numberNum >= 1 && numberNum <= 30) {
        const newStudentNumber = `${FIXED_GRADE}${classroomNum.toString().padStart(2, '0')}${numberNum.toString().padStart(2, '0')}`;
        setValue('studentNumber', newStudentNumber);
      }
    }
  }, [classroom, number, isGED, setValue]);

  const handleGraduationTypeOptionClick = (value: GraduationTypeValueEnum) => {
    setValue('graduationType', value);

    if (value === GraduationTypeValueEnum.GED) {
      setValue('schoolName', null);
      setValue('schoolAddress', null);
      setValue('studentNumber', null);
      setValue('classroom', '');
      setValue('number', '');
    } else if (!watch('schoolName')) {
      setValue('schoolName', '');
      setValue('schoolAddress', '');
      setValue('studentNumber', '');
      setValue('classroom', '');
      setValue('number', '');
    }

    setValue('graduationDate', '0000-00');
  };

  const handleYearSelectChange = (year: string) => {
    setValue('graduationDate', `${year}-${month}`);
  };

  const handleMonthSelectChange = (month: string) => {
    const paddedMonth = month.padStart(2, '0');

    setValue('graduationDate', `${year}-${paddedMonth}`);
  };

  const handleDesiredMajorChange = (fieldName: MajorFieldType, value: DesireMajorValueEnum) => {
    switch (fieldName) {
      case 'firstDesiredMajor':
        setValue('firstDesiredMajor', value);
        reset(
          { ...watch(), secondDesiredMajor: undefined, thirdDesiredMajor: undefined },
          { keepErrors: true, keepIsSubmitted: true },
        );

        return;

      case 'secondDesiredMajor':
        setValue('secondDesiredMajor', value);
        reset(
          { ...watch(), thirdDesiredMajor: undefined },
          { keepErrors: true, keepIsSubmitted: true },
        );

        return;

      case 'thirdDesiredMajor':
        setValue('thirdDesiredMajor', value);

        return;
    }
  };

  // 연/월 에러 상태 체크
  const hasYearError = showError && (!year || year === '0000');
  const hasMonthError = showError && (!month || month === '00');

  const hasClassroomError = showError && classroom === '';
  const hasNumberError = showError && number === '';

  const hasFirstMajorError =
    showError &&
    errors.firstDesiredMajor &&
    (watch('firstDesiredMajor') === undefined || watch('firstDesiredMajor') === null);
  const hasSecondMajorError =
    showError &&
    errors.secondDesiredMajor &&
    (watch('secondDesiredMajor') === undefined || watch('secondDesiredMajor') === null);
  const hasThirdMajorError =
    showError &&
    errors.thirdDesiredMajor &&
    (watch('thirdDesiredMajor') === undefined || watch('thirdDesiredMajor') === null);

  useEffect(() => {
    if (!isGED && watch('schoolName') === null) {
      setValue('schoolName', '');
      setValue('schoolAddress', '');
    }
  }, []);

  useEffect(() => {
    if (!showError) return;

    const validateForm = async () => {
      await trigger();
    };

    validateForm();
  }, [showError]);

  return (
    <div className={cn('flex', 'w-full', 'flex-col', 'items-start', 'gap-10')}>
      <div className={cn('flex', 'flex-col', 'items-start', 'gap-[0.125rem]')}>
        <h1 className={cn('text-gray-900', 'text-[1.25rem]/[1.75rem]', 'font-semibold')}>
          지원 정보를 입력해 주세요.
        </h1>
        <p className={cn('text-gray-600', 'text-[0.875rem]/[1.25rem]', 'font-normal')}>
          회원가입 시 입력한 기본 정보가 노출됩니다.
        </p>
      </div>

      <div className={cn('flex', 'items-start', 'gap-12')}>
        <div className={cn('flex', 'w-[29.75rem]', 'flex-col', 'items-start', 'gap-10')}>
          <RadioButton<GraduationTypeValueEnum>
            title={'지원자 유형'}
            list={[...graduationTypeList]}
            selectedValue={watch('graduationType')}
            handleOptionClick={handleGraduationTypeOptionClick}
            error={showError}
            required
          />

          <div className={cn('flex', 'flex-col', 'gap-3', 'w-full', 'justify-between')}>
            <CustomFormItem
              text={isGED ? '검정고시 합격일' : '출신 중학교 & 졸업일'}
              className={cn('gap-1')}
              required
              fullWidth
            >
              {!isGED && (
                <div className={cn('flex', 'gap-2')}>
                  <Input
                    placeholder="내 중학교 찾기"
                    width="full"
                    disabled={true}
                    {...register('schoolName')}
                    variant={showError && errors.schoolName ? 'error' : null}
                  />
                  <SearchDialog setValue={setValue} />
                </div>
              )}
              <div className={cn('flex', 'w-full', 'justify-between')}>
                <Select value={year === '0000' ? '' : year} onValueChange={handleYearSelectChange}>
                  <SelectTrigger
                    className={cn('w-[14.6785rem]', {
                      '!border-red-600': hasYearError,
                    })}
                  >
                    <SelectValue placeholder="연도 선택" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      <SelectLabel>연도 선택</SelectLabel>
                      {Array.from(
                        { length: PERMIT_YEAR + 1 },
                        (_, index) => START_YEAR - index,
                      ).map((year) => (
                        <SelectItem key={year} value={year.toString()}>
                          {year}년
                        </SelectItem>
                      ))}
                    </SelectGroup>
                  </SelectContent>
                </Select>
                <Select
                  value={month === '00' ? '' : Number(month).toString()}
                  onValueChange={handleMonthSelectChange}
                >
                  <SelectTrigger
                    className={cn('w-[14.6785rem]', {
                      '!border-red-600': hasMonthError,
                    })}
                  >
                    <SelectValue placeholder="월 선택" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      <SelectLabel>월 선택</SelectLabel>
                      {Array.from({ length: 12 }, (_, index) => index + 1).map((month) => (
                        <SelectItem key={month} value={month.toString()}>
                          {month}월
                        </SelectItem>
                      ))}
                    </SelectGroup>
                  </SelectContent>
                </Select>
              </div>
            </CustomFormItem>
            {!isGED && (
              <CustomFormItem text="학년/반/번호" className={cn('gap-1')} required fullWidth>
                <div className={cn('flex', 'w-full', 'justify-between')}>
                  <Select>
                    <SelectTrigger className={cn('w-[9.3785rem]')} disabled={true}>
                      <SelectValue placeholder={`${FIXED_GRADE}학년`} />
                    </SelectTrigger>
                  </Select>
                  <Select
                    value={classroom || ''}
                    onValueChange={(value) => setValue('classroom', value)}
                  >
                    <SelectTrigger
                      className={cn('w-[9.3785rem]', {
                        '!border-red-600': hasClassroomError,
                      })}
                    >
                      <SelectValue placeholder="반 선택" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectGroup>
                        <SelectLabel>반 선택</SelectLabel>
                        {Array.from({ length: 12 }, (_, i) => i + 1).map((c) => (
                          <SelectItem key={c} value={c.toString()}>
                            {c}반
                          </SelectItem>
                        ))}
                      </SelectGroup>
                    </SelectContent>
                  </Select>

                  <Select value={number || ''} onValueChange={(value) => setValue('number', value)}>
                    <SelectTrigger
                      className={cn('w-[9.3785rem]', {
                        '!border-red-600': hasNumberError,
                      })}
                    >
                      <SelectValue placeholder="번호 선택" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectGroup>
                        <SelectLabel>번호 선택</SelectLabel>
                        {Array.from({ length: 30 }, (_, i) => i + 1).map((n) => (
                          <SelectItem key={n} value={n.toString()}>
                            {n}번
                          </SelectItem>
                        ))}
                      </SelectGroup>
                    </SelectContent>
                  </Select>
                </div>
              </CustomFormItem>
            )}
          </div>
        </div>
        <div className={cn('flex', 'w-[29.75rem]', 'flex-col', 'items-start', 'gap-10')}>
          <RadioButton<ScreeningValueEnum>
            title={'전형'}
            list={[...screeningList]}
            required
            selectedValue={watch('screening')}
            handleOptionClick={(value) => setValue('screening', value)}
            error={showError}
          />
          <div className={cn('flex', 'flex-col', 'gap-7', 'w-full')}>
            <div className={cn('flex', 'flex-col', 'items-start', 'gap-1.5', 'w-full')}>
              <CustomFormItem
                text={'지원학과'}
                className={cn('gap-1')}
                required={true}
                fullWidth={true}
              >
                <div className={cn('flex', 'w-full', 'justify-between')}>
                  {majorFieldList.map((fieldName, index) => {
                    const desiredSequence = index + 1;
                    const selectedValues = [
                      desiredSequence > 1 && watch('firstDesiredMajor'),
                      desiredSequence > 2 && watch('secondDesiredMajor'),
                    ].filter((value) => typeof value === 'string');
                    const filteredMajorList = majorList.filter(
                      ({ value }) => !selectedValues.includes(value),
                    );

                    return (
                      <Select
                        key={fieldName}
                        value={watch(fieldName) || ''}
                        onValueChange={(value) =>
                          // TODO string 값으로 와서 결국 한번더 검사해주는 로직을 작성해야함
                          (value === DesireMajorValueEnum.SW ||
                            value === DesireMajorValueEnum.IOT ||
                            value === DesireMajorValueEnum.AI) &&
                          handleDesiredMajorChange(fieldName, value)
                        }
                      >
                        <SelectTrigger
                          className={cn('w-[9.3785rem]', {
                            '!border-red-600':
                              desiredSequence === 1
                                ? hasFirstMajorError
                                : desiredSequence === 2
                                  ? hasSecondMajorError
                                  : hasThirdMajorError,
                          })}
                        >
                          <SelectValue placeholder={`${desiredSequence}지망`} />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            <SelectLabel>{`${desiredSequence}지망 선택`}</SelectLabel>
                            {filteredMajorList.map(({ name, value }) => (
                              <SelectItem key={name} value={value}>
                                {name}
                              </SelectItem>
                            ))}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    );
                  })}
                </div>
              </CustomFormItem>
            </div>
            <div
              className={cn(
                'flex',
                'flex-col',
                'w-full',
                'h-[5.75rem]',
                'justify-center',
                'items-center',
                'bg-slate-100',
                'rounded-md',
              )}
            >
              <ul
                className={cn(
                  'flex',
                  'flex-col',
                  'items-start',
                  'w-[26.5rem]',
                  'gap-1',
                  'list-disc',
                )}
              >
                {majorIntroductions.map(({ name, description }, index) => (
                  <li key={index} className={cn('text-slate-600', 'text-[0.75rem]/[1.125rem]')}>
                    <span className={cn('font-semibold')}>{name}</span>
                    <span className={cn('font-normal')}> - {description}</span>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Step2Register;

'use client';

import { useEffect } from 'react';
import {
  FormState,
  UseFormRegister,
  UseFormSetValue,
  UseFormTrigger,
  UseFormWatch,
} from 'react-hook-form';

import { RelationshipWithGuardianValueEnum, Step3FormType } from '@repo/types';
import { cn } from '@repo/utils';

import { CustomFormItem, RadioButton } from '../../';
import { Input } from '../../../shadcn';

interface Step3RegisterProps {
  register: UseFormRegister<Step3FormType>;
  setValue: UseFormSetValue<Step3FormType>;
  watch: UseFormWatch<Step3FormType>;
  trigger: UseFormTrigger<Step3FormType>;
  formState: FormState<Step3FormType>;
  isCandidate: boolean;
  showError: boolean;
}
const relationshipWithGuardianList = [
  { name: '부', value: RelationshipWithGuardianValueEnum.FATHER },
  { name: '모', value: RelationshipWithGuardianValueEnum.MOTHER },
  { name: '기타 (직접입력)', value: RelationshipWithGuardianValueEnum.OTHER },
] as const;

const Step3Register = ({
  register,
  setValue,
  watch,
  trigger,
  formState: { errors },
  isCandidate,
  showError,
}: Step3RegisterProps) => {
  const handleRelationshipWithGuardianOptionClick = (value: RelationshipWithGuardianValueEnum) => {
    if (value !== RelationshipWithGuardianValueEnum.OTHER) {
      setValue('otherRelationshipWithGuardian', null);
    }

    setValue('relationshipWithGuardian', value);
  };

  useEffect(() => {
    if (isCandidate) {
      setValue('schoolTeacherName', watch('schoolTeacherName') ?? '');
      setValue('schoolTeacherPhoneNumber', watch('schoolTeacherPhoneNumber') ?? '');
    }

    if (!isCandidate) {
      setValue('schoolTeacherName', null);
      setValue('schoolTeacherPhoneNumber', null);
    }
  }, []);

  useEffect(() => {
    if (!showError) return;

    const validateForm = async () => {
      await trigger();
    };

    validateForm();
  }, [showError]);

  return (
    <div className={cn('flex', 'w-full', 'flex-col', 'items-start', 'gap-10')}>
      <div className={cn('flex', 'flex-col', 'items-start', 'gap-0.5')}>
        <h1 className={cn('text-gray-900', 'text-[1.25rem]/[1.75rem]', 'font-semibold')}>
          보호자 / 담임선생님 정보를 입력해 주세요.
        </h1>
        <p className={cn('text-gray-600', 'text-[0.875rem]/[1.25rem]', 'font-normal')}>
          회원가입 시 입력한 기본 정보가 노출됩니다.
        </p>
      </div>

      <div className={cn('flex', 'items-start', 'gap-12')}>
        <div className={cn('flex', 'w-[29.75rem]', 'flex-col', 'items-start', 'gap-8')}>
          <CustomFormItem
            text={'보호자 이름 / 휴대폰 번호'}
            className={cn('gap-1')}
            required
            fullWidth
          >
            <Input
              placeholder="보호자 이름 입력"
              width="full"
              {...register('guardianName')}
              variant={showError && errors.guardianName ? 'error' : null}
            />
            <Input
              placeholder="보호자 휴대폰 번호 입력 (하이픈 '-' 제외)"
              width="full"
              {...register('guardianPhoneNumber')}
              variant={showError && errors.guardianPhoneNumber ? 'error' : null}
            />
          </CustomFormItem>
          <div className={cn('flex', 'flex-col', 'gap-3')}>
            <RadioButton<RelationshipWithGuardianValueEnum>
              title={'보호자 관계'}
              list={[...relationshipWithGuardianList]}
              selectedValue={watch('relationshipWithGuardian')}
              handleOptionClick={handleRelationshipWithGuardianOptionClick}
              error={showError}
              required
            />
            {watch('relationshipWithGuardian') === RelationshipWithGuardianValueEnum.OTHER && (
              <Input
                placeholder="직접 입력"
                {...register('otherRelationshipWithGuardian')}
                variant={
                  showError &&
                  (errors.otherRelationshipWithGuardian ||
                    watch('otherRelationshipWithGuardian') === null)
                    ? 'error'
                    : null
                }
              />
            )}
          </div>
        </div>
        <div className={cn('flex', 'w-[29.75rem]', 'flex-col', 'items-start', 'gap-8')}>
          {isCandidate && (
            <CustomFormItem
              text={'담임선생님 이름 / 연락처'}
              className={cn('gap-1')}
              required
              fullWidth
            >
              <Input
                placeholder="담임선생님 이름 입력"
                width="full"
                {...register('schoolTeacherName')}
                variant={showError && errors.schoolTeacherName ? 'error' : null}
              />
              <Input
                placeholder="담임선생님 연락처 입력 (하이픈 '-' 제외)"
                width="full"
                {...register('schoolTeacherPhoneNumber')}
                variant={showError && errors.schoolTeacherPhoneNumber ? 'error' : null}
              />
            </CustomFormItem>
          )}
        </div>
      </div>
    </div>
  );
};

export default Step3Register;

/* eslint-disable @typescript-eslint/naming-convention */
'use client';

import { useEffect, useRef, useState } from 'react';
import {
  Control,
  UseFormRegister,
  UseFormSetValue,
  UseFormUnregister,
  UseFormWatch,
  UseFormStateReturn,
  UseFormTrigger,
  UseFormGetValues,
  get,
} from 'react-hook-form';

import { GENERAL_SUBJECTS } from '@repo/constants';
import {
  AchievementType,
  FreeSemesterValueEnum,
  GraduationTypeValueEnum,
  LiberalSystemValueEnum,
  Step4FormType,
} from '@repo/types';
import { cn } from '@repo/utils';

import { FormController, LiberalSystemSwitch } from '../../';
import { Input } from '../../../shadcn';
import { ArtPhysicalForm, FreeGradeForm, FreeSemesterForm, NonSubjectForm } from '../../form';

const formWrapper = [
  'flex',
  'flex-col',
  'gap-[0.75rem]',
  'text-slate-900',
  'text-lg',
  'font-semibold',
  'leading-7',
  'w-full',
];

const widthConvertor: { [key: string]: string } = {
  freeGrade_GRADUATION: 'w-[42.9375rem]',
  freeGrade_CANDIDATE: 'w-[35.4375rem]',
  freeSemester_GRADUATION: 'w-[43.4375rem]',
  freeSemester_CANDIDATE: 'w-[36.1em]',
};

const freeGradeCandidateArray = [
  { title: '2학년 1학기', field: 'achievement2_1' },
  { title: '2학년 2학기', field: 'achievement2_2' },
  { title: '3학년 1학기', field: 'achievement3_1' },
] as const;

const freeGradeGraduateArray = [
  { title: '2학년 1학기', field: 'achievement2_1' },
  { title: '2학년 2학기', field: 'achievement2_2' },
  { title: '3학년 1학기', field: 'achievement3_1' },
  { title: '3학년 2학기', field: 'achievement3_2' },
] as const;

const freeSemesterCandidateArray = [
  {
    title: '1학년 1학기',
    field: 'achievement1_1',
    value: FreeSemesterValueEnum['1-1'],
  },
  {
    title: '1학년 2학기',
    field: 'achievement1_2',
    value: FreeSemesterValueEnum['1-2'],
  },
  {
    title: '2학년 1학기',
    field: 'achievement2_1',
    value: FreeSemesterValueEnum['2-1'],
  },
  {
    title: '2학년 2학기',
    field: 'achievement2_2',
    value: FreeSemesterValueEnum['2-2'],
  },
  {
    title: '3학년 1학기',
    field: 'achievement3_1',
    value: FreeSemesterValueEnum['3-1'],
  },
] as const;

const freeSemesterGraduateArray = [
  {
    title: '2학년 1학기',
    field: 'achievement2_1',
    value: FreeSemesterValueEnum['2-1'],
  },
  {
    title: '2학년 2학기',
    field: 'achievement2_2',
    value: FreeSemesterValueEnum['2-2'],
  },
  {
    title: '3학년 1학기',
    field: 'achievement3_1',
    value: FreeSemesterValueEnum['3-1'],
  },
  {
    title: '3학년 2학기',
    field: 'achievement3_2',
    value: FreeSemesterValueEnum['3-2'],
  },
] as const;

interface Step4RegisterProps {
  type?: 'client' | 'admin' | 'calculate';
  graduationType: GraduationTypeValueEnum;
  register: UseFormRegister<Step4FormType>;
  unregister: UseFormUnregister<Step4FormType>;
  setValue: UseFormSetValue<Step4FormType>;
  watch: UseFormWatch<Step4FormType>;
  trigger: UseFormTrigger<Step4FormType>;
  getValues: UseFormGetValues<Step4FormType>;
  control: Control<Step4FormType>;
  formState: UseFormStateReturn<Step4FormType>;
  isGED: boolean;
  isCandidate: boolean;
  isGraduate: boolean;
  showError: boolean;
  clearStepError: () => void;
}

const Step4Register = ({
  register,
  setValue,
  control,
  watch,
  trigger,
  formState,
  unregister,
  getValues,
  type,
  graduationType,
  isGED,
  isCandidate,
  isGraduate,
  showError,
  clearStepError,
}: Step4RegisterProps) => {
  const [subjectArray, setSubjectArray] = useState<string[]>([...GENERAL_SUBJECTS]);
  const defaultSubjectLength = GENERAL_SUBJECTS.length;

  const isCalculate = type === 'calculate';
  const isFreeSemester = watch('liberalSystem') === LiberalSystemValueEnum.FREE_SEMESTER;
  const isFreeGrade = watch('liberalSystem') === LiberalSystemValueEnum.FREE_GRADE;

  const achievementList: AchievementType[] = isFreeSemester
    ? isCandidate
      ? [...freeSemesterCandidateArray]
      : [...freeSemesterGraduateArray]
    : isCandidate
      ? [...freeGradeCandidateArray]
      : [...freeGradeGraduateArray];

  const handleDeleteSubjectClick = (idx: number) => {
    const filteredSubjects = subjectArray.filter((_, i) => i !== idx);
    unregister(`newSubjects.${idx - defaultSubjectLength}`);
    unregister(`achievement1_1.${idx}`, undefined);
    unregister(`achievement1_2.${idx}`, undefined);
    unregister(`achievement2_1.${idx}`, undefined);
    unregister(`achievement2_2.${idx}`, undefined);
    unregister(`achievement3_1.${idx}`, undefined);
    unregister(`achievement3_2.${idx}`, undefined);
    setSubjectArray(filteredSubjects);

    const newSubjects = watch('newSubjects');
    const score1_1 = watch('achievement1_1');
    const score1_2 = watch('achievement1_2');
    const score2_1 = watch('achievement2_1');
    const score2_2 = watch('achievement2_2');
    const score3_1 = watch('achievement3_1');
    const score3_2 = watch('achievement3_2');

    setValue(
      'newSubjects',
      newSubjects && newSubjects.filter((_, i) => idx - defaultSubjectLength !== i),
    ); // newSubjects 배열에서 인덱스가 N인 값 제거
    setValue('achievement1_1', score1_1 && score1_1.filter((_, i) => i !== idx));
    setValue('achievement1_2', score1_2 && score1_2.filter((_, i) => i !== idx));
    setValue('achievement2_1', score2_1 && score2_1.filter((_, i) => i !== idx));
    setValue('achievement2_2', score2_2 && score2_2.filter((_, i) => i !== idx));
    setValue('achievement3_1', score3_1 && score3_1.filter((_, i) => i !== idx));
    setValue('achievement3_2', score3_2 && score3_2.filter((_, i) => i !== idx)); // score3_2 배열에서 인덱스가 기본과목.length + index인 값 제거 (삭제 버튼 클릭한 인덱스 제거)
  };

  const handleAddSubjectClick = (subjectName?: string) => {
    const newSubject = subjectName
      ? subjectName
      : `추가과목 ${subjectArray.length - defaultSubjectLength}`;
    setSubjectArray((prev) => [...prev, newSubject]);

    if (watch('liberalSystem') === LiberalSystemValueEnum.FREE_GRADE) {
      achievementList.forEach(({ field }) =>
        setValue(`${field}.${subjectArray.length}`, watch(`${field}.${subjectArray.length}`)),
      );
    } else {
      achievementList.forEach(
        ({ field, value }) =>
          value !== watch('freeSemester') &&
          setValue(`${field}.${subjectArray.length}`, watch(`${field}.${subjectArray.length}`)),
      );
    }
  };

  useEffect(() => {
    if (isGED) {
      setValue('liberalSystem', null);
      setValue('achievement1_1', null);
      setValue('achievement1_2', null);
      setValue('achievement2_1', null);
      setValue('achievement2_2', null);
      setValue('achievement3_1', null);
      setValue('achievement3_2', null);
      setValue('artsPhysicalAchievement', null);
      setValue('absentDays', null);
      setValue('attendanceDays', null);
      setValue('volunteerTime', null);
      setValue('freeSemester', null);
    } else {
      setValue('gedAvgScore', null);
      setValue('liberalSystem', watch('liberalSystem') || LiberalSystemValueEnum.FREE_GRADE);
    }

    const newSubject = watch('newSubjects');

    if (newSubject && newSubject.length) {
      newSubject.forEach((subjectName) => handleAddSubjectClick(subjectName));
    }
  }, []);

  const prevIsFreeSemesterRef = useRef(isFreeSemester);
  const prevIsFreeGradeRef = useRef(isFreeGrade);

  useEffect(() => {
    const modeChanged =
      prevIsFreeSemesterRef.current !== isFreeSemester ||
      prevIsFreeGradeRef.current !== isFreeGrade;

    prevIsFreeSemesterRef.current = isFreeSemester;
    prevIsFreeGradeRef.current = isFreeGrade;

    if (!modeChanged || isGED) return;

    setValue('artsPhysicalAchievement', null);
  }, [isFreeSemester, isFreeGrade, isGED, setValue]);

  useEffect(() => {
    if (clearStepError) clearStepError();
  }, [isFreeGrade, isFreeSemester]);

  const validateForm = async () => {
    await trigger();
  };

  useEffect(() => {
    if (!showError) return;

    validateForm();
  }, [showError]);

  return (
    <>
      <div className={cn(['w-[66.5rem]', 'flex', 'flex-col', type === 'admin' && 'pb-20'])}>
        <h1
          className={cn(
            'text-[1.25rem]',
            'font-normal',
            'font-semibold',
            'leading-[1.75rem]',
            'tracking-[-0.00625rem]',
            'text-gray-900',
          )}
        >
          {isCalculate ? '모의 성적 계산하기' : '성적을 입력해 주세요.'}
        </h1>
        <p
          className={cn(
            'text-sm',
            'font-normal',
            'leading-5',
            'text-gray-600',
            'mt-[0.125rem]',
            'mb-[2rem]',
          )}
        >
          {isCalculate
            ? '성적을 정확히 입력해 주세요.'
            : '계산을 위해 지원자님의 정확한 성적을 입력해주세요.'}
        </p>
        {graduationType === GraduationTypeValueEnum.GED ? (
          <form onSubmit={(e) => e.preventDefault()}>
            <div className={cn('w-[18.75rem]', 'flex', 'flex-col', 'gap-1')}>
              <p className={cn('text-slate-900', 'text-[0.875rem]/[1.25rem]')}>
                검정고시 평균 점수 <span className={cn('text-red-600')}>*</span>
              </p>
              <Input
                type="text"
                {...register('gedAvgScore', {
                  setValueAs: (v) => {
                    const num = Number(v);
                    return !num ? undefined : num;
                  },
                })}
                placeholder="평균 점수 입력"
                onInput={(e: React.FormEvent<HTMLInputElement>) => {
                  const input = e.currentTarget;
                  input.value = input.value.replace(/[^0-9.]/g, '').replace(/(\..*?)\..*/g, '$1');
                }}
                variant={
                  (Boolean(get(formState.errors, 'gedAvgScore')) ||
                    watch('gedAvgScore') === undefined) &&
                  showError
                    ? 'error'
                    : null
                }
              />
            </div>
          </form>
        ) : (
          <div
            className={cn(
              'flex',
              'h-lvh',
              'justify-center',
              'bg-white',
              'w-full',
              'h-fit',
              'gap-[2.5rem]',
            )}
          >
            <FormController className={cn('mt-[5.625rem]')} />
            <form
              onSubmit={(e) => e.preventDefault()}
              className={cn('flex', 'flex-col', 'items-center')}
            >
              <LiberalSystemSwitch
                isFreeGrade={isFreeGrade}
                isFreeSemester={isFreeSemester}
                setValue={setValue}
                className={cn('mb-[3rem]')}
              />
              <div
                className={cn(
                  'flex',
                  'flex-col',
                  'gap-[2.5rem]',
                  'items-center',
                  widthConvertor[`${watch('liberalSystem')}_${graduationType}`],
                )}
              >
                <div className={cn([...formWrapper])}>
                  <div className={cn('flex', 'justify-between', 'items-center')}>일반교과 성적</div>
                  {isFreeGrade && (
                    <FreeGradeForm
                      achievementList={achievementList}
                      register={register}
                      setValue={setValue}
                      subjectArray={subjectArray}
                      watch={watch}
                      control={control}
                      errors={formState.errors}
                      handleDeleteSubjectClick={handleDeleteSubjectClick}
                      isGraduate={isGraduate}
                      showError={showError}
                      getValues={getValues}
                      validateForm={validateForm}
                    />
                  )}
                  {isFreeSemester && (
                    <FreeSemesterForm
                      achievementList={achievementList}
                      register={register}
                      setValue={setValue}
                      subjectArray={subjectArray}
                      watch={watch}
                      errors={formState.errors}
                      handleDeleteSubjectClick={handleDeleteSubjectClick}
                      freeSemester={watch('freeSemester')}
                      isGraduate={isGraduate}
                      showError={showError}
                      getValues={getValues}
                      validateForm={validateForm}
                    />
                  )}
                  <button
                    type="button"
                    onClick={() => handleAddSubjectClick()}
                    className={cn(
                      'text-sm',
                      'font-semibold',
                      'leading-6',
                      'text-[#0F172A]',
                      'h-[2.5rem]',
                      'w-full',
                      'flex',
                      'items-center',
                      'justify-center',
                      'rounded-md',
                      'border-[0.0625rem]',
                      'border-slate-200',
                    )}
                  >
                    + 과목 추가하기
                  </button>
                </div>
                <div id="artPhysicalSubject" className={cn([...formWrapper])}>
                  예체능 교과 성적
                  <ArtPhysicalForm
                    graduationType={graduationType}
                    setValue={setValue}
                    watch={watch}
                    isFreeGrade={isFreeGrade}
                    isFreeSemester={isFreeSemester}
                    isGraduate={isGraduate}
                    showError={showError}
                    freeSemester={watch('freeSemester')}
                  />
                </div>
                <div id="nonSubject" className={cn([...formWrapper])}>
                  <div className={cn('w-full', 'flex', 'justify-between')}>
                    비교과 내용
                    <div
                      className={cn(
                        'flex',
                        'items-center',
                        'justify-center',
                        'gap-1',
                        'text-red-600',
                        'text-[0.75rem]/[1.25rem]',
                        'font-semibold',
                      )}
                    >
                      <p>*</p>
                      <p>9월 30일까지의 미인정 결석·지각·조퇴·결과 및 봉사시간 입력</p>
                    </div>
                  </div>
                  <NonSubjectForm
                    register={register}
                    trigger={trigger}
                    errors={formState.errors}
                    isFreeGrade={isFreeGrade}
                    isGraduate={isGraduate}
                    showError={showError}
                    validateForm={validateForm}
                  />
                </div>
              </div>
            </form>
          </div>
        )}
      </div>
    </>
  );
};

export default Step4Register;
